        String literalEscape = "\\u0006"; // This is the literal string \u0006
        System.out.println("\nLiteral escape length: " + literalEscape.length());
        System.out.println("Char values:");
        for (int i = 0; i < literalEscape.length(); i++) {
            System.out.println("  " + i + ": " + (int) literalEscape.charAt(i) + " ('" + literalEscape.charAt(i) + "')");
        }

        String result2 = removeControlChars(literalEscape);
        System.out.println("Result for literal escape: '" + result2 + "'");
    }

